INSERT INTO products (name, description, price, original_price, category, image_url, images, stock, rating, rating_count, brand, specifications) VALUES
('Samsung Galaxy S24 Ultra', 'The Samsung Galaxy S24 Ultra features a stunning 6.8-inch Dynamic AMOLED display, 200MP camera system, and built-in S Pen. Powered by Snapdragon 8 Gen 3 processor with 12GB RAM.', 129999.00, 144999.00, 'Electronics', 'https://images.unsplash.com/photo-1610945265064-0e34e5519bbf?w=400', ARRAY['https://images.unsplash.com/photo-1610945265064-0e34e5519bbf?w=600','https://images.unsplash.com/photo-1511707171634-5f897ff02aa9?w=600','https://images.unsplash.com/photo-1592899677977-9c10ca588bbd?w=600'], 25, 4.5, 2847, 'Samsung', '{"Display": "6.8 inch Dynamic AMOLED 2X", "Processor": "Snapdragon 8 Gen 3", "RAM": "12 GB", "Storage": "256 GB", "Camera": "200 MP + 12 MP + 50 MP + 10 MP", "Battery": "5000 mAh"}'),

('Sony WH-1000XM5 Headphones', 'Industry-leading noise canceling with Auto NC Optimizer. Crystal clear hands-free calling with 4 beamforming microphones. Up to 30 hours battery life with quick charging.', 28990.00, 34990.00, 'Electronics', 'https://images.unsplash.com/photo-1618366712010-f4ae9c647dcb?w=400', ARRAY['https://images.unsplash.com/photo-1618366712010-f4ae9c647dcb?w=600','https://images.unsplash.com/photo-1583394838336-acd977736f90?w=600','https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600'], 50, 4.6, 1523, 'Sony', '{"Type": "Over-Ear Wireless", "Driver": "30mm", "Noise Cancelling": "Yes - Adaptive", "Battery": "30 hours", "Weight": "250g", "Connectivity": "Bluetooth 5.2"}'),

('Apple MacBook Air M3', 'Supercharged by the M3 chip. With up to 18 hours of battery life. A stunningly thin design. And a brilliant 15.3-inch Liquid Retina display. MacBook Air is built for intelligence.', 134900.00, 149900.00, 'Electronics', 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=400', ARRAY['https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=600','https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=600','https://images.unsplash.com/photo-1541807084-5c52b6b3adef?w=600'], 15, 4.8, 967, 'Apple', '{"Display": "15.3 inch Liquid Retina", "Processor": "Apple M3", "RAM": "8 GB", "Storage": "256 GB SSD", "Battery": "Up to 18 hours", "Weight": "1.51 kg"}'),

('JBL Charge 5 Bluetooth Speaker', 'JBL Charge 5 delivers bold JBL Original Pro Sound with its optimized long excursion driver and separate tweeter. Enjoy up to 20 hours of playtime with waterproof and dustproof design.', 14999.00, 18999.00, 'Electronics', 'https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=400', ARRAY['https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=600','https://images.unsplash.com/photo-1589003077984-894e133dabab?w=600'], 35, 4.4, 3201, 'JBL', '{"Type": "Portable Bluetooth Speaker", "Battery": "20 hours", "Waterproof": "IP67", "Driver": "52mm woofer + tweeter", "Weight": "960g"}'),

('Canon EOS R50 Mirrorless Camera', 'Compact and lightweight mirrorless camera with 24.2MP APS-C CMOS sensor. Features Dual Pixel CMOS AF II and 4K video recording. Perfect for content creators.', 74990.00, 84990.00, 'Electronics', 'https://images.unsplash.com/photo-1516035069371-29a1b244cc32?w=400', ARRAY['https://images.unsplash.com/photo-1516035069371-29a1b244cc32?w=600','https://images.unsplash.com/photo-1502920917128-1aa500764cbd?w=600','https://images.unsplash.com/photo-1606986628253-e29c4563f77a?w=600'], 10, 4.7, 432, 'Canon', '{"Sensor": "24.2MP APS-C CMOS", "Video": "4K 30fps", "AF Points": "651", "ISO Range": "100-32000", "Weight": "375g"}');

