('Dyson V15 Detect Cordless Vacuum', 'Dyson most powerful, intelligent cordless vacuum. Reveals invisible dust with a laser. Automatically adapts suction power. Up to 60 minutes runtime.', 52900.00, 62900.00, 'Home & Kitchen', 'https://images.unsplash.com/photo-1558317374-067fb5f30001?w=400', ARRAY['https://images.unsplash.com/photo-1558317374-067fb5f30001?w=600','https://images.unsplash.com/photo-1527515637462-cee1395c1c73?w=600'], 8, 4.8, 876, 'Dyson', '{"Motor": "Dyson Hyperdymium", "Runtime": "Up to 60 min", "Suction": "230 AW", "Dustbin": "0.76L", "Weight": "3.1 kg", "Filtration": "Whole-machine HEPA"}'),

('Philips Air Fryer HD9200', 'Fry with up to 90% less fat. Rapid Air Technology for crispy results without oil. 4.1L capacity, 1400W power. Easy clean with removable non-stick drawer.', 6499.00, 9999.00, 'Home & Kitchen', 'https://images.unsplash.com/photo-1626509653291-18d9a934b9db?w=400', ARRAY['https://images.unsplash.com/photo-1626509653291-18d9a934b9db?w=600'], 45, 4.4, 12543, 'Philips', '{"Capacity": "4.1 Liters", "Power": "1400W", "Technology": "Rapid Air", "Temperature": "80-200°C", "Timer": "Up to 30 min"}'),

('Prestige Iris 750W Mixer Grinder', 'Powerful 750W motor mixer grinder with 3 stainless steel jars. Super efficient blades for fine grinding. Sturdy ABS body with 2-year warranty.', 3299.00, 4999.00, 'Home & Kitchen', 'https://images.unsplash.com/photo-1570222094114-d054a817e56b?w=400', ARRAY['https://images.unsplash.com/photo-1570222094114-d054a817e56b?w=600'], 60, 4.2, 6782, 'Prestige', '{"Power": "750W", "Jars": "3 Stainless Steel", "Speed": "3 Speed + Pulse", "Body": "ABS Plastic", "Warranty": "2 Years"}');

-- Books
INSERT INTO products (name, description, price, original_price, category, image_url, images, stock, rating, rating_count, brand, specifications) VALUES
('Atomic Habits by James Clear', 'No matter your goals, Atomic Habits offers a proven framework for improving every day. James Clear reveals practical strategies to form good habits, break bad ones, and master the tiny behaviors that lead to remarkable results.', 499.00, 799.00, 'Books', 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=400', ARRAY['https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=600','https://images.unsplash.com/photo-1512820790803-83ca734da794?w=600'], 200, 4.7, 89432, 'Penguin Random House', '{"Author": "James Clear", "Pages": "320", "Language": "English", "Publisher": "Penguin Random House", "Format": "Paperback", "ISBN": "978-0735211292"}'),

('The Psychology of Money by Morgan Housel', 'Timeless lessons on wealth, greed, and happiness. Morgan Housel shares 19 short stories exploring the strange ways people think about money and teaches you how to make better sense of one of lifes most important topics.', 399.00, 599.00, 'Books', 'https://images.unsplash.com/photo-1592496431122-2349e0fbc666?w=400', ARRAY['https://images.unsplash.com/photo-1592496431122-2349e0fbc666?w=600'], 150, 4.6, 56234, 'Jaico Publishing', '{"Author": "Morgan Housel", "Pages": "256", "Language": "English", "Publisher": "Jaico Publishing House", "Format": "Paperback"}'),

('Clean Code by Robert C. Martin', 'A handbook of agile software craftsmanship. Even bad code can function. But if code isnt clean, it can bring a development organization to its knees. This book is a must-read for any developer.', 2999.00, 3999.00, 'Books', 'https://images.unsplash.com/photo-1532012197267-da84d127e765?w=400', ARRAY['https://images.unsplash.com/photo-1532012197267-da84d127e765?w=600'], 40, 4.5, 12876, 'Pearson', '{"Author": "Robert C. Martin", "Pages": "464", "Language": "English", "Publisher": "Pearson", "Format": "Paperback", "ISBN": "978-0132350884"}');

